// Build feed items from database sources
const allItems = $('Fetch Sources').all();
const sources = allItems.map(item => item.json);

const feeds = sources
  .filter(s => s.feed_url && s.feed_url.startsWith('http'))
  .map(s => ({
    json: {
      source_id: s.id,
      source_slug: s.slug,
      source_name: s.name,
      source_region: s.region || 'Global',
      source_language: s.language || 'en',
      url: s.feed_url
    }
  }));

if (feeds.length === 0) {
  return [{ json: { _error: 'No active RSS sources found', _skip: true } }];
}

return feeds;

// Parse raw RSS/Atom/RDF XML and extract items.
// CRITICAL: Carry source metadata through from Feed List by index.
const items = $input.all();
const feedListItems = $('Feed List').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  // Get source metadata for this feed by matching index
  const source = feedListItems[i]?.json || {};

  const xml = item.json.data || item.json.body || item.json.response || '';
  if (!xml || typeof xml !== 'string') continue;

  // Skip HTML responses (broken feeds return HTML instead of RSS)
  if (xml.trim().startsWith('<!DOCTYPE html') || xml.trim().startsWith('<html')) continue;

  // Extract <item> (RSS 2.0 / RDF 1.0) or <entry> (Atom) blocks
  const itemBlocks = xml.match(/<item[\s>][\s\S]*?<\/item>/gi) || 
                     xml.match(/<entry[\s>][\s\S]*?<\/entry>/gi) || [];

  if (itemBlocks.length === 0) continue;

  for (const block of itemBlocks) {
    const getTag = (tag) => {
      // Try CDATA first, then regular content
      const cdataRe = new RegExp('<' + tag + '[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]></' + tag + '>', 'i');
      const plainRe = new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)</' + tag + '>', 'i');
      const m = block.match(cdataRe) || block.match(plainRe);
      return m ? m[1].trim() : null;
    };

    const getAttr = (tag, attr) => {
      const re = new RegExp('<' + tag + '[^>]*?' + attr + '=["\']([^"\']*)["\']', 'i');
      const m = block.match(re);
      return m ? m[1] : null;
    };

    // Extract image URL from multiple possible tags
    const imageUrl = getAttr('media:thumbnail', 'url') || 
                     getAttr('media:content', 'url') ||
                     getAttr('enclosure', 'url') ||
                     getAttr('image', 'url') ||
                     null;

    const title = getTag('title') || '';
    const link = getTag('link') || getAttr('link', 'href') || '';
    const pubDate = getTag('pubDate') || getTag('published') || getTag('updated') || getTag('dc:date') || '';
    const description = getTag('description') || getTag('content:encoded') || getTag('content') || getTag('summary') || '';
    const creator = getTag('dc:creator') || getTag('author') || null;
    const guid = getTag('guid') || getTag('id') || link;

    // Clean CDATA wrappers and HTML entities
    const clean = (s) => s ? s.replace(/^<!\[CDATA\[/, '').replace(/\]\]>$/, '').replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&#39;/g,"'").trim() : s;

    if (!title && !link) continue;

    let isoDate;
    try {
      isoDate = pubDate ? new Date(pubDate).toISOString() : new Date().toISOString();
    } catch(e) {
      isoDate = new Date().toISOString();
    }

    results.push({
      json: {
        title: clean(title),
        link: clean(link),
        pubDate: pubDate,
        'content:encoded': description,
        description: description,
        contentSnippet: clean(description).replace(/<[^>]+>/g, '').substring(0, 500),
        guid: clean(guid),
        isoDate: isoDate,
        imageUrl: imageUrl,
        creator: creator,
        // CARRY SOURCE METADATA — this is the key fix
        _source_id: source.source_id,
        _source_name: source.source_name,
        _source_slug: source.source_slug,
        _source_region: source.source_region,
        _source_language: source.source_language
      }
    });
  }
}

return results.length > 0 ? results : [{ json: { _skip: true } }];

// Process RSS items into enriched article records.
// Source metadata is now carried from Parse RSS via _source_* fields.
const items = $input.all();

// FNV-1a hash using charCodeAt
function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return h >>> 0;
}

// Keyword-based topic classification
const TOPIC_RULES = [
  { topic: 'Economics', keywords: ['gdp', 'inflation', 'interest rate', 'central bank', 'monetary policy', 'fiscal', 'recession', 'economic growth', 'unemployment', 'debt', 'deficit', 'imf', 'world bank', 'oecd', 'ppi', 'cpi', 'yield', 'economy', 'economist'] },
  { topic: 'Geopolitics', keywords: ['war', 'conflict', 'military', 'sanctions', 'nato', 'security council', 'territorial', 'sovereignty', 'diplomatic', 'diplomacy', 'embassy', 'ceasefire', 'nuclear', 'missile', 'troops', 'invasion', 'alliance', 'geopolit', 'talks', 'summit', 'negotiat', 'peace deal', 'prisoner exchange', 'regime', 'kremlin', 'pentagon', 'white house', 'foreign minister', 'foreign policy', 'zelensky', 'putin', 'ukraine', 'gaza', 'israel', 'iran', 'xi jinping', 'trump'] },
  { topic: 'Business', keywords: ['ceo', 'revenue', 'profit', 'merger', 'acquisition', 'ipo', 'startup', 'market share', 'quarterly', 'earnings', 'shareholder', 'board of directors', 'layoff', 'restructur', 'company', 'corporate', 'billion', 'million deal'] },
  { topic: 'Technology', keywords: ['ai ', 'artificial intelligence', 'chip', 'semiconductor', 'software', 'data center', 'cloud computing', 'cyber', 'quantum', 'blockchain', 'robot', 'autonomous', '5g', 'tech giant', 'openai', 'google', 'apple', 'microsoft', 'nvidia', 'deepfake'] },
  { topic: 'Energy', keywords: ['oil', 'gas price', 'opec', 'renewable', 'solar', 'wind power', 'nuclear energy', 'hydrogen', 'lng', 'crude', 'barrel', 'carbon', 'emission', 'grid', 'energy'] },
  { topic: 'Defense', keywords: ['defense', 'defence', 'arms', 'weapon', 'military spending', 'procurement', 'fighter jet', 'navy', 'army', 'air force', 'drone', 'radar', 'artillery', 'air defense'] },
  { topic: 'Trade', keywords: ['tariff', 'trade war', 'trade deal', 'customs', 'wto', 'free trade', 'supply chain', 'logistics', 'freight', 'shipping', 'quota', 'dumping', 'export ban', 'import ban'] },
  { topic: 'Climate', keywords: ['climate', 'global warming', 'paris agreement', 'cop2', 'greenhouse', 'net zero', 'sustainable', 'deforestation', 'biodiversity', 'flood', 'drought', 'wildfire'] },
  { topic: 'Finance', keywords: ['stock', 'bond', 'forex', 'bitcoin', 'crypto', 'banking', 'hedge fund', 'private equity', 'venture capital', 'fintech', 'insurance', 'credit', 'loan', 'mortgage', 'wall street', 'investor'] },
  { topic: 'Healthcare', keywords: ['health', 'pharma', 'vaccine', 'pandemic', 'hospital', 'medical', 'drug', 'clinical trial', 'fda', 'biotech', 'patient', 'disease'] },
  { topic: 'Infrastructure', keywords: ['infrastructure', 'railway', 'highway', 'bridge', 'construction', 'housing', 'real estate', 'transit', 'airport', 'broadband'] },
  { topic: 'Legal', keywords: ['court', 'lawsuit', 'regulation', 'compliance', 'antitrust', 'gdpr', 'legislation', 'ruling', 'verdict', 'prosecutor', 'attorney', 'legal'] }
];

function classifyTopics(title, content) {
  const text = (title + ' ' + (content || '')).toLowerCase();
  const matched = [];
  for (const rule of TOPIC_RULES) {
    for (const kw of rule.keywords) {
      if (text.includes(kw)) {
        matched.push(rule.topic);
        break;
      }
    }
  }
  if (matched.length === 0) return ['General'];
  return matched.slice(0, 5);
}

const articles = items
  .filter(item => item.json.title && item.json.link && !item.json._skip)
  .slice(0, 500)
  .map(item => {
    // Use source metadata carried through from Parse RSS
    const sourceId = item.json._source_id;
    const sourceName = item.json._source_name;
    const sourceSlug = item.json._source_slug;
    const sourceRegion = item.json._source_region || 'Global';
    const sourceLanguage = item.json._source_language || 'en';

    // Skip articles with no source attribution
    if (!sourceId || !sourceName) return null;

    const content = (item.json['content:encoded'] || item.json.description || item.json.title || '')
      .replace(/<[^>]*>/g, '').trim();

    const author = item.json.creator || item.json['dc:creator'] || item.json.author || null;

    const h = fnv1a(item.json.link);
    const urlHash = h.toString(16).padStart(8, '0');

    const pad = (s, n) => s.padStart(n, '0').slice(0, n);
    const h1 = h.toString(16);
    const h2 = (h >>> 4).toString(16);
    const h3 = (h >>> 8).toString(16);
    const h4 = (h >>> 12).toString(16);
    const h5 = (h >>> 16).toString(16);
    const articleId = `${pad(h1,8)}-${pad(h2,4)}-4${pad(h3,3)}-8${pad(h4,3)}-${pad(h5,12)}`;

    const publishedAt = item.json.isoDate || item.json.pubDate || item.json.date || null;
    const topicTags = classifyTopics(item.json.title, content);

    return {
      json: {
        pinecone_id: `${sourceSlug}-${urlHash}`,
        article_id: articleId,
        title: item.json.title.trim(),
        url: item.json.link.trim(),
        content: content.substring(0, 2000),
        excerpt: content.substring(0, 300),
        source: sourceName,
        source_slug: sourceSlug,
        source_id: sourceId,
        source_name: sourceName,
        author: author,
        language: sourceLanguage,
        region: sourceRegion,
        topic_tags: topicTags,
        is_processed: true,
        published_at: publishedAt || new Date().toISOString(),
        image_url: item.json.imageUrl || null,
      }
    };
  })
  .filter(a => a !== null);

return articles.length > 0 ? articles : [{ json: { _skip: true } }];
